//api.playcanvas.com/engine/classes/GSplatComponent.html",children:"Gaussian Splats"}),". Gaussian Splats are a new way of capturing and rendering high quality 3D content. They capture the shape and lighting of a scene in a way that produces incredibly high quality results."]}),"\n",(0,s.jsxs)(t.p,{children:["The ",(0,s.jsx)(t.code,{children:"useSplat"})," hooks accepts ply or sog files or any other files that can be loaded by the engine."]}),"\n",(0,s.jsx)(t.h2,{id:"usage",children:"Usage"}),"\n",(0,s.jsxs)(t.p,{children:["You can load a Gaussian Splat asset with the ",(0,s.jsx)(t.a,{href:"../../api/hooks/use-asset#usesplat",children:(0,s.jsx)(t.code,{children:"useSplat"})})," hook and then use the ",(0,s.jsx)(t.code,{children:"<GSplat>"})," component to render it."]}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-tsx",children:"const { asset } = useSplat('/assets/toy-cat.sog');\n<GSplat asset={asset} />\n"})}),"\n",(0,s.jsx)(o.G,{label:"Load and render a Gaussian Splat",filename:"gsplat-example.jsx",code:"import { Entity } from '@playcanvas/react';\nimport { GSplat, Camera } from '@playcanvas/react/components';\nimport { useSplat } from '@playcanvas/react/hooks';\n\nexport const GSplatExample = () => {\n    // Load the Gaussian Splat asset\n    const { asset } = useSplat('/assets/toy-cat.sog');\n\n    // If the asset is not loaded, return null\n    if (!asset) return null;\n\n    // Return the GSplat component\n    return (\n        <Entity rotation={[180, 180, 0]} position={[0, -0.7, 0]} >\n            <GSplat asset={asset} />\n        </Entity>\n    );\n};\n\n",showDemo:!0,children:(0,s.jsx)(i.l,{children:(0,s.jsx)(o.C,{useLight:!1,useGrid:!1,camera:[2,1,2],useControls:!0,children:(0,s.jsx)(c,{})})})}),"\n",(0,s.jsxs)(t.p,{children:["Learn more about the ",(0,s.jsx)(t.a,{href:"https://api.playcanvas.com/engine/classes/GSplatComponent.html",children:"GSplat Component"})," in the PlayCanvas documentation."]}),"\n",(0,s.jsx)(t.h2,{id:"properties",children:"Properties"}),"\n",(0,s.jsx)(a,{data:'[{"name":"default","description":"","entries":[{"name":"customAabb","description":"Sets a custom object space bounding box for visibility culling of the attached gsplat.\\nGets the custom object space bounding box for visibility culling of the attached gsplat.\\nReturns the custom AABB if set, otherwise falls back to the resource\'s AABB.","optional":true,"type":{"displayName":"BoundingBox | null","types":[{"name":"BoundingBox","url":"https://api.playcanvas.com/engine/classes/BoundingBox.html"}]}},{"name":"material","description":"Sets the material used to render the gsplat.\\n\\n**Note:** This setter is only supported when unified is `false`. When it\'s true, multiple\\ngsplat components share a single material per camera/layer combination. To access materials in\\nunified mode, use GSplatComponentSystem#getMaterial .\\nGets the material used to render the gsplat.\\n\\n**Note:** This getter returns `null` when unified is `true`. In unified mode, materials are\\norganized per camera/layer combination rather than per component. To access materials in\\nunified mode, use GSplatComponentSystem#getMaterial .","optional":true,"type":{"displayName":"ShaderMaterial | null","types":[{"name":"ShaderMaterial","url":"https://api.playcanvas.com/engine/classes/ShaderMaterial.html"}]}},{"name":"highQualitySH","description":"Sets whether to use the high quality or the approximate (but fast) spherical-harmonic calculation when rendering SOG data.\\n\\nThe low quality approximation evaluates the scene\'s spherical harmonic contributions\\nalong the camera\'s Z-axis instead of using each gaussian\'s view vector. This results\\nin gaussians being accurate at the center of the screen and becoming less accurate\\nas they appear further from the center. This is a good trade-off for performance\\nwhen rendering large SOG datasets, especially on mobile devices.\\n\\nDefaults to false.\\nGets whether the high quality (true) or the fast approximate (false) spherical-harmonic calculation is used when rendering SOG data.","optional":true,"type":{"displayName":"boolean","types":[{"name":"false","url":null},{"name":"true","url":null}]}},{"name":"castShadows","description":"Sets whether gsplat will cast shadows for lights that have shadow casting enabled. Defaults\\nto false.\\nGets whether gsplat will cast shadows for lights that have shadow casting enabled.","optional":true,"type":{"displayName":"boolean","types":[{"name":"false","url":null},{"name":"true","url":null}]}},{"name":"lodDistances","description":"Sets LOD distance thresholds used by octree-based gsplat rendering. The provided array\\nis copied.\\nGets a copy of LOD distance thresholds previously set, or null when not set.","optional":true,"type":{"displayName":"number[] | null","types":[{"name":"Array","url":null}]}},{"name":"splatBudget","description":"Sets the target number of splats to render for this component. The system will adjust LOD\\nlevels bidirectionally to reach this budget:\\n- When over budget: degrades quality for less important geometry\\n- When under budget: upgrades quality for more important geometry\\n\\nThis ensures optimal use of available rendering budget while prioritizing quality for\\ncloser/more important geometry.\\n\\nSet to 0 to disable the budget (default). When disabled, optimal LOD is determined purely\\nby distance and configured LOD parameters.\\n\\nOnly applies to octree-based gsplat rendering in unified mode.\\nGets the splat budget limit for this component.","optional":true,"type":{"displayName":"number","types":[{"name":"number","url":null}]}},{"name":"unified","description":"Sets whether to use the unified gsplat rendering. Default is false.\\n\\nNote: Material handling differs between modes. When unified is false, use\\nGSplatComponent#material . When unified is true, materials are shared per\\ncamera/layer - use GSplatComponentSystem#getMaterial  instead.\\nGets whether to use the unified gsplat rendering.","optional":true,"type":{"displayName":"boolean","types":[{"name":"false","url":null},{"name":"true","url":null}]}},{"name":"workBufferUpdate","description":"Sets the work buffer update mode. Only applicable in unified rendering mode.\\n\\nIn unified mode, splat data is rendered to a work buffer only when needed (e.g., when\\ntransforms change). Can be:\\n- WORKBUFFER_UPDATE_AUTO: Update only when needed (default).\\n- WORKBUFFER_UPDATE_ONCE: Force update this frame, then switch to AUTO.\\n- WORKBUFFER_UPDATE_ALWAYS: Update every frame.\\n\\nThis is typically useful when using custom shader code via workBufferModifier  that\\ndepends on external factors like time or animated uniforms.\\n\\nNote: WORKBUFFER_UPDATE_ALWAYS has a performance impact as it re-renders\\nall splat data to the work buffer every frame. Where possible, consider using shader\\ncustomization on the unified gsplat material (`app.scene.gsplat.material`) which is\\napplied during final rendering without re-rendering the work buffer.\\nGets the work buffer update mode.","optional":true,"type":{"displayName":"number","types":[{"name":"number","url":null}]}},{"name":"layers","description":"Sets an array of layer IDs (Layer#id ) to which this gsplat should belong. Don\'t\\npush, pop, splice or modify this array. If you want to change it, set a new one instead.\\nGets the array of layer IDs (Layer#id ) to which this gsplat belongs.","optional":true,"type":{"displayName":"number[]","types":[{"name":"Array","url":null}]}},{"name":"asset","description":"Sets the gsplat asset for this gsplat component. Can also be an asset id.\\nGets the gsplat asset id for this gsplat component.","optional":true,"type":{"displayName":"number | Asset","types":[{"name":"number","url":null},{"name":"Asset","url":"https://api.playcanvas.com/engine/classes/Asset.html"}]}},{"name":"resource","description":"Sets a GSplat resource directly (for procedural/container splats).\\nWhen set, this takes precedence over the asset property.\\nGets the GSplat resource. Returns the directly set resource if available,\\notherwise returns the resource from the assigned asset.","optional":true,"type":{"displayName":"GSplatResourceBase | null","types":[{"name":"GSplatResourceBase","url":"https://api.playcanvas.com/engine/classes/GSplatResourceBase.html"}]}},{"name":"system","description":"The ComponentSystem used to create this Component.","optional":true,"type":{"displayName":"ComponentSystem","types":[{"name":"ComponentSystem","url":"https://api.playcanvas.com/engine/classes/ComponentSystem.html"}]}},{"name":"entity","description":"The Entity that this Component is attached to.","optional":true,"type":{"displayName":"Entity","types":[{"name":"Entity","url":"https://api.playcanvas.com/engine/classes/Entity.html"}]}},{"name":"enabled","description":"Sets the enabled state of the component.\\nGets the enabled state of the component.","optional":true,"type":{"displayName":"boolean","types":[{"name":"false","url":null},{"name":"true","url":null}]}}]}]'})]})}function f(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(y,{...e})}):y(e)}},7184(e,t,a){a.d(t,{C:()=>A,G:()=>G});var n=a(11470),s=a(19365),r=a(59849),o=a(96540),i=a(95293),l=a(75390),p=a(18676),d=a(58817),c=a(19748),u=a(83395),h=a(43025),m=a(10977),g=a(7306),y=a(55937),f=a(78692),b=a(8939),w=a(40050),x=a(93953),S=a(27351),v=a(74848);const j="// \u2191 imports hidden",G=({code:e,label:t,filename:a,language:i="jsx",showDemo:p=!1,showViewSourceButton:d=!0,showControls:c=!0,children:u})=>{const[h,m]=(0,o.useState)(0);if(!u||!e)return console.error("CodeExample: code and children are required"),null;return(0,v.jsxs)(n.A,{defaultValue:h>0?"Code":p?"Demo":"Code",children:[(0,v.jsx)(s.A,{value:"Demo",children:(0,v.jsxs)("div",{className:"code-example-demo",children:[u,d&&(0,v.jsxs)("div",{className:"code-example-demo-footer",children:[t," - ",(0,v.jsx)("a",{href:"#",onClick:e=>{e.preventDefault(),m(e=>e